+
+    private static string DecodePythonString(string text)
+    {
+        if (!text.Contains('\\'))
+        {
+            return text;
+        }
+
+        var sb = new StringBuilder(text.Length);
+        for (var i = 0; i < text.Length; i++)
+        {
+            var c = text[i];
+            if (c != '\\' || i + 1 >= text.Length)
+            {
+                sb.Append(c);
+                continue;
+            }
+
+            var next = text[++i];
+            switch (next)
+            {
+                case '\\':
+                case '\'':
+                case '"':
+                    sb.Append(next);
+                    break;
+                case 'n':
+                    sb.Append('\n');
+                    break;
+                case 'r':
+                    sb.Append('\r');
+                    break;
+                case 't':
+                    sb.Append('\t');
+                    break;
+                default:
+                    sb.Append('\\');
+                    sb.Append(next);
+                    break;
+            }
+        }
+
+        return sb.ToString();
+    }
 }

