+                if (i + 2 >= value.length()) {
+                    throw new AwsException("InvalidArgument", "Invalid copy source: " + value, 400);
+                }
+                int high = Character.digit(value.charAt(i + 1), 16);
+                int low = Character.digit(value.charAt(i + 2), 16);
+                if (high < 0 || low < 0) {
+                    throw new AwsException("InvalidArgument", "Invalid copy source: " + value, 400);
+                }
