+fn handle_deletion_at_edge_of_insertion(
+    a_hunks: &[Hunk],
+    b_hunks: &[Hunk],
+    input: &imara_diff::InternedInput<&[u8]>,
+    current_tokens: &[imara_diff::Token],
+    out: &mut Vec<u8>,
+    ancestor_integrated_until: &mut u32,
+) -> bool {
+    fn insertion_and_deletion<'a>(a_hunks: &'a [Hunk], b_hunks: &'a [Hunk]) -> Option<(&'a Hunk, &'a Hunk)> {
+        let insertion = a_hunks
+            .iter()
+            .find(|hunk| hunk.side != Side::Ancestor && hunk.before.is_empty() && !hunk.after.is_empty())?;
+        let deletion = b_hunks
+            .iter()
+            .find(|hunk| hunk.side != Side::Ancestor && !hunk.before.is_empty() && hunk.after.is_empty())?;
+        let only_insertion_and_ancestor = a_hunks
+            .iter()
+            .all(|hunk| std::ptr::eq(hunk, insertion) || hunk.side == Side::Ancestor);
+        let only_deletion_and_ancestor = b_hunks
+            .iter()
+            .all(|hunk| std::ptr::eq(hunk, deletion) || hunk.side == Side::Ancestor);
+        only_insertion_and_ancestor
+            .then_some(())
+            .zip(only_deletion_and_ancestor.then_some(()))
+            .map(|_| (insertion, deletion))
+    }
+
+    let Some((insertion, deletion)) = insertion_and_deletion(a_hunks, b_hunks)
+        .or_else(|| insertion_and_deletion(b_hunks, a_hunks))
+        .filter(|(insertion, deletion)| {
+            deletion.before.start == insertion.before.start || deletion.before.end == insertion.before.start
+        })
+    else {
+        return false;
+    };
+
+    write_ancestor(input, *ancestor_integrated_until, insertion.before.start as usize, out);
+    write_hunks(std::slice::from_ref(insertion), input, current_tokens, out);
+    *ancestor_integrated_until = deletion.before.end;
+    true
+}
