+
+/// Expands directly affected tasks through the task graph in the same direction
+/// as `Engine::retain_affected_tasks` (affected tasks plus transitive
+/// dependents), then adds dependencies for every selected task. The final
+/// dependency expansion keeps unchanged topological prerequisites (for example
+/// `^build`) in the graph when a dependent task is affected by its own inputs.
+fn include_dependencies_of_affected_and_dependents(
+    engine: &Engine,
+    directly_affected: HashSet<TaskId<'static>>,
+) -> HashSet<TaskId<'static>> {
+    let task_graph = engine.task_graph();
+    let task_lookup = engine.task_lookup();
+
+    let mut affected = directly_affected.clone();
+    let mut queue = VecDeque::new();
+
+    for task_id in &directly_affected {
+        if let Some(&idx) = task_lookup.get(task_id) {
+            queue.push_back(idx);
+        }
+    }
+
+    while let Some(idx) = queue.pop_front() {
+        for dependent_idx in task_graph.neighbors_directed(idx, petgraph::Direction::Incoming) {
+            let Some(turborepo_engine::TaskNode::Task(dependent_id)) =
+                task_graph.node_weight(dependent_idx)
+            else {
+                continue;
+            };
+
+            if affected.insert(dependent_id.clone()) {
+                queue.push_back(dependent_idx);
+            }
+        }
+    }
+
+    let dependencies = engine.collect_task_dependencies(&affected);
+    affected.extend(dependencies);
+    affected
 }

